const input = $input.first().json;
const query = (input.query || 'top').trim();

try {
  let stories = [];

  if (query.toLowerCase() === 'top' || query === '') {
    const topIds = await helpers.httpRequest({
      method: 'GET',
      url: 'https://hacker-news.firebaseio.com/v0/topstories.json'
    });

    const top5 = topIds.slice(0, 5);
    for (const id of top5) {
      const item = await helpers.httpRequest({
        method: 'GET',
        url: 'https://hacker-news.firebaseio.com/v0/item/' + id + '.json'
      });
      stories.push({
        title: item.title || '',
        url: item.url || 'https://news.ycombinator.com/item?id=' + id,
        points: item.score || 0,
        author: item.by || '',
        comments: item.descendants || 0
      });
    }
  } else {
    const res = await helpers.httpRequest({
      method: 'GET',
      url: 'https://hn.algolia.com/api/v1/search?query=' + encodeURIComponent(query) + '&tags=story&hitsPerPage=5'
    });

    for (const hit of (res.hits || [])) {
      stories.push({
        title: hit.title || '',
        url: hit.url || 'https://news.ycombinator.com/item?id=' + hit.objectID,
        points: hit.points || 0,
        author: hit.author || '',
        comments: hit.num_comments || 0
      });
    }
  }

  if (stories.length === 0) {
    return [{ json: { result: 'No stories found for: ' + query } }];
  }

  let r = 'Hacker News results' + (query.toLowerCase() === 'top' ? ' (Top Stories)' : ' for "' + query + '"') + ':\n\n';
  for (let i = 0; i < stories.length; i++) {
    const s = stories[i];
    r += (i + 1) + '. ' + s.title + '\n';
    r += '   URL: ' + s.url + '\n';
    r += '   Points: ' + s.points + ' | Author: ' + s.author + ' | Comments: ' + s.comments + '\n\n';
  }

  return [{ json: { result: r } }];
} catch (e) {
  return [{ json: { error: 'Failed to fetch Hacker News: ' + e.message } }];
}
